import{_ as t,o as r,c as a,a1 as o}from"./chunks/framework.BX4nIuL2.js";const c=JSON.parse('{"title":"Post process","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/3_3dprinter/8.postprocess.md","filePath":"courses/fab-course/doc/3_3dprinter/8.postprocess.md"}'),s={name:"courses/fab-course/doc/3_3dprinter/8.postprocess.md"};function i(p,e,l,n,h,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="post-process" tabindex="-1">Post process <a class="header-anchor" href="#post-process" aria-label="Permalink to &quot;Post process&quot;">​</a></h1><p>We print <a href="https://a360.co/2MZ0cBf" target="_blank" rel="noreferrer">one model</a> and attach the Cura parameter</p><p>| Name |Parameter | Name |Parameter | | --- | --- | --- | --- | --- | --- | | Layer high | 0.1mm | Wall thickness | 3mm | | Infill density | 30% |Infill pattern | Lines | |Printing Temperature | 200 |Diameter | 1.75mm | | Printing speed | 60mm/s |Infill speed | 100mm/s| | Outer wall speed | 30 |Support speed | 60 | | Support place | everywhere |Over hang angle | 50 | | Build plate adhesive type | Raft |Raft extra margin | 15mm |</p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/QQ20190621-202528.jpg" alt=""></p><p><img src="https://github.com/bobwu0214/dm360.github.io/blob/master/Img/111.jpg?raw=true" alt=""></p><h2 id="_1-remove-support" tabindex="-1">1. Remove support <a class="header-anchor" href="#_1-remove-support" aria-label="Permalink to &quot;1. Remove support&quot;">​</a></h2><p>Prints with support material will require post-processing to remove the support structures. This can be achieved by breaking the support structures from the build material.</p><ul><li>Tear the inner support structure</li></ul><p>Start by removing the walls of the support structure with gripping pliers. This allows you to quickly tear away the majority of the inner support structure. <img src="https://github.com/bobwu0214/dm360.github.io/blob/master/Img/pier.jpg?raw=true" alt=""></p><ul><li>Pull the Breakaway support from the build material</li></ul><p>After removing most of the support structure, the remaining part(s) can be pulled from the build material. Use cutting pliers to grab the Breakaway support in a corner and try to carefully get underneath it, then bend it upwards. Repeat this for several corners, so that you can loosen the support from the model around the corners. After this, pull the Breakaway support from the model.</p><ul><li>Peel the last traces from the model</li></ul><p>Sometimes a final layer of the support material will remain after pulling the Breakaway support from the build material. If this happens, use cutting pliers to peel it off from a loose edge. Any leftover traces on the model can be removed with tweezers.</p><p><img src="https://github.com/bobwu0214/dm360.github.io/blob/master/Img/beforepolish.jpg?raw=true" alt=""></p><h2 id="_2-polish-model" tabindex="-1">2. Polish model <a class="header-anchor" href="#_2-polish-model" aria-label="Permalink to &quot;2. Polish model&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/blob/master/Img/sandpaper.jpg?raw=true" alt=""> We would use sandpaper to polish model with water ,choice sandpaper 180 for rough polish, 240 for polish and 320 for finish polish <img src="https://github.com/bobwu0214/dm360.github.io/blob/master/Img/polish.jpg?raw=true" alt=""> The following is the result <img src="https://github.com/bobwu0214/dm360.github.io/blob/master/Img/finish.jpg?raw=true" alt=""></p><ul><li>3D model :<a href="https://a360.co/2MZ0cBf" target="_blank" rel="noreferrer">https://a360.co/2MZ0cBf</a></li></ul><h2 id="_3-painting" tabindex="-1">3. Painting <a class="header-anchor" href="#_3-painting" aria-label="Permalink to &quot;3. Painting&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/SLAtank.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/slapaint.png" alt=""> polish,painting and assemble for the final prototype.</p><h2 id="_4-varnish-from-translucent-to-transparent" tabindex="-1">4. Varnish(from translucent to transparent ) <a class="header-anchor" href="#_4-varnish-from-translucent-to-transparent" aria-label="Permalink to &quot;4. Varnish(from translucent to transparent )&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/slatransparent.png" alt=""> This method need use professional Polish mehtod （sandpaper polish at least P800 ）and then varnish.</p>',21)])])}const d=t(s,[["render",i]]);export{c as __pageData,d as default};
